/**
 * Fetch Execution List
 * 
 * Query params:
 * - workflow_id: Filter by workflow (optional)
 * - execution_id: Filter by specific execution (optional)  
 * - offset: Pagination offset (default: 0)
 * - limit: Number of results (default: 500, max: 500)
 */

const query = $input.first().json.query || {};
const workflowId = query.workflow_id || null;
const executionId = query.execution_id || null;
const offset = parseInt(query.offset) || 0;
const limit = Math.min(parseInt(query.limit) || 500, 500);

// Build filter object for n8n API
const filters = {};

if (workflowId) {
  filters.workflowId = workflowId;
}

if (executionId) {
  filters.id = executionId;
}

return [{
  json: {
    filters,
    offset,
    limit,
    workflowId,
    executionId
  }
}];

/**
 * Format Execution List Response
 * Returns cleaned execution data for the frontend
 */

const executions = $input.all().map(item => {
  const exec = item.json.execution;

  // Calculate duration
  let duration = null;
  if (exec.startedAt && exec.stoppedAt) {
    duration = new Date(exec.stoppedAt) - new Date(exec.startedAt);
  }

  return {
    id: exec.id,
    status: exec.status === 'success' ? 'success' : 'error',
    mode: exec.mode,
    startedAt: exec.startedAt,
    stoppedAt: exec.stoppedAt,
    duration,
    workflowId: exec.workflowId,
    workflowName: exec.workflowData?.name || 'Unknown Workflow',
    retryOf: exec.retryOf,
    retrySuccessId: exec.retrySuccessId
  };
});

// Get workflow name from first execution
const workflowName = executions.length > 0 ? executions[0].workflowName : null;

return [{
  json: {
    success: true,
    workflowName,
    count: executions.length,
    executions
  }
}];

/**
 * Parse Execution Details Request
 */

const query = $input.first().json.query || {};
const executionId = query.execution_id;

if (!executionId) {
  throw new Error('execution_id is required');
}

return [{ json: { executionId } }];

/**
 * Format Execution Details Response
 * Sources all data exclusively from the execution JSON.
 * The "Get Workflow" node is no longer needed and can be removed.
 *
 * CHANGE SUMMARY:
 *   - Replaced $('Get Workflow').first().json with execution.workflowData
 *   - workflowData is n8n's built-in snapshot of the workflow at execution time,
 *     so it always reflects what actually ran — including nodes that may have since
 *     been deleted or changed in the live workflow.
 */

const row = $('Get Execution').first().json;
const execution = row.execution;

// Parse execution data if it's a string
let execData = execution.data;
if (typeof execData === 'string') {
  try {
    execData = JSON.parse(execData);
  } catch (e) {
    execData = {};
  }
}

// Use the workflow snapshot stored inside the execution (replaces Get Workflow)
const workflow = execution.workflowData || {};

const runData = execData?.resultData?.runData || {};
const globalError = execData?.resultData?.error;

// Determine overall status
let status = 'success';
if (globalError || execution.status === 'error' || execution.status === 'crashed') {
  status = 'error';
} else if (execution.status === 'running' || execution.status === 'waiting') {
  status = 'running';
}

// Process nodes with their execution data
const nodes = (workflow.nodes || []).map(node => {
  const nodeRuns = runData[node.name] || [];
  const lastRun = nodeRuns[nodeRuns.length - 1];
  const hasRun = !!lastRun;
  const hasError = !!(lastRun?.error);

  let nodeStatus = 'not-executed';
  if (hasError) nodeStatus = 'error';
  else if (hasRun) nodeStatus = 'success';

  // Get output data
  const outputData = lastRun?.data?.main || [];
  const outputCount = outputData.reduce((sum, arr) => sum + (arr?.length || 0), 0);

  // Get input sources
  const inputSources = lastRun?.source || [];

  return {
    id: node.id,
    name: node.name,
    type: node.type,
    typeVersion: node.typeVersion || 1,
    position: node.position || [0, 0],
    parameters: node.parameters || {},
    onError: node.onError,
    credentials: node.credentials ? Object.keys(node.credentials) : [],
    status: nodeStatus,
    hasRun,
    hasError,
    error: lastRun?.error || null,
    startTime: lastRun?.startTime || null,
    executionTime: lastRun?.executionTime || null,
    inputSources,
    outputData,
    outputCount
  };
});

// Process connections
const connections = [];
Object.entries(workflow.connections || {}).forEach(([fromName, outputs]) => {
  if (!outputs.main) return;
  outputs.main.forEach((targets, outputIndex) => {
    if (!targets) return;
    targets.forEach(target => {
      const fromNode = nodes.find(n => n.name === fromName);
      const toNode = nodes.find(n => n.name === target.node);
      if (fromNode && toNode) {
        // Aggregate item count across ALL runs for this output port
        let itemCount = 0;
        const nodeRuns = runData[fromName] || [];
        nodeRuns.forEach(run => {
          const portData = run?.data?.main?.[outputIndex];
          if (portData) {
            itemCount += portData.length;
          }
        });

        connections.push({
          from: fromNode.id,
          fromName,
          to: toNode.id,
          toName: target.node,
          fromPort: outputIndex,
          toPort: target.index || 0,
          itemCount
        });
      }
    });
  });
});

// Calculate stats
const totalNodes = nodes.length;
const executedNodes = nodes.filter(n => n.hasRun).length;
const errorNodes = nodes.filter(n => n.hasError).length;

return [{
  json: {
    success: true,
    executionId: execution.id,
    workflowId: workflow.id,
    workflowName: workflow.name,
    status,
    mode: execution.mode,
    startedAt: execution.startedAt,
    stoppedAt: execution.stoppedAt,
    retryOf: execution.retryOf,
    retrySuccessId: execution.retrySuccessId,

    // Error info if present
    error: globalError ? {
      message: globalError.message,
      nodeName: globalError.node?.name,
      nodeType: globalError.node?.type,
      stack: globalError.stack
    } : null,

    // Stats
    stats: {
      totalNodes,
      executedNodes,
      errorNodes
    },

    // Full workflow structure for rendering
    workflow: {
      id: workflow.id,
      name: workflow.name,
      nodes,
      connections: workflow.connections
    },

    // Pre-processed nodes and connections
    nodes,
    connections,

    // Raw execution data (for detailed inspection)
    execution: {
      id: execution.id,
      data: execData
    }
  }
}];

parameters.query:
SELECT * FROM errors_executions
WHERE workflow_id = '{{ $json.filters.workflowId }}' 
ORDER BY id DESC
LIMIT {{ $json.limit }}
OFFSET {{ $json.offset }}
